// Font roles:
//   CARTOON_BOX  → titles (Part 2, Part 3, Sneak Peek)
//   HOPE_CARTOON → on-screen text (bumper, resume card)
//   TITAN_ONE    → subtitle / rewind label

export const CARTOON_BOX  = 'CartoonBox';
export const HOPE_CARTOON = 'HopeCartoon';
export const TITAN_ONE    = 'TitanOne';

// Remotion waits for document.fonts.ready automatically before rendering —
// no delayRender needed. Just inject @font-face and Remotion handles the rest.
if (typeof document !== 'undefined') {
  const s = document.createElement('style');
  s.textContent = `@font-face { font-family: 'CartoonBox'; src: url('data:font/otf;base64,') format('opentype'); font-weight: normal; font-style: normal; }\n@font-face { font-family: 'HopeCartoon'; src: url('data:font/otf;base64,') format('opentype'); font-weight: normal; font-style: normal; }\n@font-face { font-family: 'TitanOne'; src: url('data:font/ttf;base64,') format('truetype'); font-weight: normal; font-style: normal; }`;
  document.head.appendChild(s);
}
